import React from 'react';
import clsx from 'clsx';

import Icon from '@components/ui/Icon';

import { admonition as admonition_cssClass, alert as alert_cssClass, warn as warn_cssClass, tip as tip_cssClass } from './admonition.module.css';

/**
 * React component to display an admonition
 * @param {Object} prop - Prop object passed to this component
 * @param {?('tip'|'alert'|'warn')} [prop.type] - Type of admonition. Default is blue info
 * @param {?String} [prop.title] - Title of Admonition
 * @param {?String} [prop.customIcon] - Custom icon to override the default icons for each type of admonition
 * @param {?String} [prop.className] - Additional css class to append to the admoition container element
 * @param {String|JSX.Element} prop.children - Message to display
 */
export default function Admonition({ type, title, customIcon, className, children, ...restProps }) {
	if (type === 'tip') {
		// green tip
		return (
			<div className={clsx(admonition_cssClass, tip_cssClass, className && typeof className === 'string' && className)} {...restProps}>
				<div>
					{customIcon && typeof customIcon === 'string' ? <Icon icon={customIcon} /> : <Icon icon="award" />}
					{title || 'Tip'}
				</div>
				<div>{children}</div>
			</div>
		);
	} else if (type === 'alert') {
		// yellow alert
		return (
			<div className={clsx(admonition_cssClass, alert_cssClass, className && typeof className === 'string' && className)} {...restProps}>
				<div>
					{customIcon && typeof customIcon === 'string' ? <Icon icon={customIcon} /> : <Icon icon="alert-triangle" />}
					{title || 'Attention'}
				</div>
				<div>{children}</div>
			</div>
		);
	} else if (type === 'warn') {
		// red warning
		return (
			<div className={clsx(admonition_cssClass, warn_cssClass, className && typeof className === 'string' && className)} {...restProps}>
				<div>
					{customIcon && typeof customIcon === 'string' ? <Icon icon={customIcon} /> : <Icon icon="alert-triangle" />}
					{title || 'Warning'}
				</div>
				<div>{children}</div>
			</div>
		);
	} else {
		//the default blue note
		return (
			<div className={clsx(admonition_cssClass, className && typeof className === 'string' && className)} {...restProps}>
				<div>
					{customIcon && typeof customIcon === 'string' ? <Icon icon={customIcon} /> : <Icon icon="alert-circle" />}
					{title || 'Note'}
				</div>
				<div>{children}</div>
			</div>
		);
	}
}
